package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.tools.RszConstant;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.dmfa.KengetalDmfa;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

@AllArgsConstructor
public abstract class AbstractBijdrageMetPercentageBase implements BijdrageMetPercentage {
    private static final int SCHUIF_FACTOR_100 = 2;
    private final RszConstantService rszConstantService;

    public BigDecimal getWerkgeversPercentageZonderType(LocalDate zoekDatum, WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal dmfapplWnkengetal) {
        RszConstant rszConstant =
                rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalEnDatum(werkgeversCategorie, dmfapplWnkengetal, zoekDatum);
        return getWerkgeversPercentage(rszConstant);
    }

    public BigDecimal getWerkgeversPercentage(LocalDate zoekDatum, WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal dmfapplWnkengetal, Integer type) {
        RszConstant rszConstant = getRszConstant(zoekDatum, werkgeversCategorie, dmfapplWnkengetal, type);
        return getWerkgeversPercentage(rszConstant);
    }

    public BigDecimal getWerkgeversPercentage(RszConstant rszConstant) {
        BigDecimal werkgeversPercentage = rszConstant == null ? BigDecimal.ZERO : rszConstant.getWerkgeversPercentage();
        return werkgeversPercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    public RszConstant getRszConstant(LocalDate zoekDatum, WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal dmfapplWnkengetal, Integer type) {
        return rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(werkgeversCategorie, dmfapplWnkengetal, type, zoekDatum);
    }

    public KengetalDmfa makeKengetalDmfa(SleutelGegevens gegevens) {
        return new KengetalDmfa(gegevens.getWerknemersKengetal());
    }
}
